head.script:
//전역변수
scwin.pos_groupCode = 0;
scwin.g_sAcctDeptCd = ""; // 귀속부서 
scwin.g_sCurrDate = "";  // 시스템일자 
scwin.g_sUserId = ""; // 사용자id
scwin.err_message = "";


//-------------------------------------------------------------------------
// TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    //로그인 정보 추출
    var login = $c.data.getMemInfo();
    scwin.g_sAcctDeptCd = login.acctDeptCd;
    scwin.g_sCurrDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.g_sUserId = login.empNo;
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. onPageLoad 에서 호출 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    ed_regYy.setValue(scwin.g_sCurrDate.substring(0, 4));
    ica_tmnDt.setValue(scwin.g_sCurrDate);
    lc_tmnYn.getValue("2");
    $c.gus.cfDisableObjects(ed_crnNm);
};

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->귀속부서, 2:조회->거래처
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = async function (cd, nm) {
    await udc_crn.cfCommonPopUp(function (rtnList) {
        if (!$c.gus.cfIsNull(rtnList)) {
            if (rtnList[0] == "N/A") return;
            ed_crn.setValue(rtnList[0]);	// 코드값
            ed_crnNm.setValue(rtnList[1]);	// 코드명
        } else {
            ed_crn.setValue("");
            ed_crnNm.setValue("");
        }
    }, cd, "", "T", null, null, null, null, null, null, null, null, null); //사업자번호
};

//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.(그리드용)
//-------------------------------------------------------------------------
scwin.f_checkCommonPopUp = async function (select_code, pCode, pName, Row) {
    var code = ds_saleCreditInfo.getCellData(Row, pCode);
    // if (code.trim() != "") {
    //     scwin.f_openCommonPopUp(select_code, pCode, pName, Row, "T");
    // } else {
    //     ds_saleCreditInfo.setCellData(Row, pCode, "");
    //     ds_saleCreditInfo.setCellData(Row, pName, "");
    // }

    if (code.trim() == "") {
        ds_saleCreditInfo.setCellData(Row, pCode, "");
        ds_saleCreditInfo.setCellData(Row, pName, "");
    }
    await scwin.f_openCommonPopUp(select_code, pCode, pName, Row, "T");

};

//-------------------------------------------------------------------------
// 사업자팝업
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (select_code, pCode, pName, Row, pClose) {
    var code = ds_saleCreditInfo.getCellData(Row, pCode);

    if ($c.gus.cfIsNull(code) || code == "") code = "";

    switch (select_code) {
        // 사업자번호 PopUp 호출
        case '2':
            //tobe추가 : 셋팅전 값 초기화
            ds_saleCreditInfo.setCellData(Row, "crn", "");
            ds_saleCreditInfo.setCellData(Row, "crnNm", "");
            await udc_crngd.cfCommonPopUpAsync(function (rtnList) {
                if (rtnList[0] != "N/A") {
                    $c.gus.cfSetGridReturnValue(rtnList, ds_saleCreditInfo, Row, "crn", "crnNm")
                }
            },
                code, "", pClose, null, null, null, null, null, null, null, null, null, null, null, null, null); // 여신대상사업자번호

            break;

        // 엑셀업로드용 사업자번호 PopUp 호출	
        case '3':
            await udc_crngd.cfCommonPopUpAsync(function (rtnList) {
                if (!$c.gus.cfIsNull(rtnList)) {
                    if (rtnList[0] == "N/A") return;
                    ds_upload.setCellData(Row, "crn", rtnList[0]);	// 코드값
                    ds_upload.setCellData(Row, "crnNm", rtnList[1]);	// 코드명
                } else {
                    scwin.err_message = scwin.err_message + ds_upload.getCellData(Row, "crn") + ", ";
                    ds_upload.setCellData(Row, "crn", "");
                    return false;
                }
            }, ds_upload.getCellData(Row, "crn"), "", pClose, null, null, null, null, null, null, null, null, null, null, null, null, null); // 여신대상사업자번호
            break;
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    // 필수 조회조건 입력 여부(등록년도) Check
    var check = await $c.gus.cfValidate([ed_regYy], null, true)
    if (!check) {
        return false;
    }

    //조회데이터 셋팅
    dma_search.set("regYy", ed_regYy.getValue());
    dma_search.set("crn", ed_crn.getValue());
    dma_search.set("tmnYn", lc_tmnYn.getValue());

    $c.sbm.execute(sbm_search);
};

scwin.sbm_search_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        ica_tmnDt.setValue("");
        // 조회된 건수를 Grid 왼쪽 하단에 표시한다.
        var rowCnt = ds_saleCreditInfo.getRowCount();
        totalRows.setValue(rowCnt);

        if (rowCnt != 0) {
            gr_saleCreditInfo.setFocusedCell(0, 0); //tobe추가 : 조회시, 포커스가 맨 상단 값에 셋팅되어있음
        } else { // rowCnt가 0일때
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        }
    };
};

//-------------------------------------------------------------------------
// 엑셀 업로드용 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve2 = async function () {
    // 필수 조회조건 입력 여부(등록년도) Check
    if (!await $c.gus.cfValidate([ed_regYy], null, true)) {
        return false;
    };

    //조회데이터 셋팅
    dma_search.set("regYy", ed_regYy.getValue());
    dma_search.set("crn", "");
    dma_search.set("tmnYn", "2");

    $c.sbm.execute(sbm_search2);
};

scwin.sbm_search2_submitdone = async function (e) {
    //for= ds_upSearch event = OnLoadCompleted(rowCnt)
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        var rowCnt = ds_upSearch.getRowCount();
        if (await $c.win.confirm(ed_regYy.getValue() + "년에 등록된 데이터가 " + rowCnt + "건이 있습니다.기존데이터 삭제후 저장됩니다. 진행하시겠습니까?")) {

            if (ds_temp.getRowCount() == 0) {//if (ds_excel.getRowCount() == 0) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
                return;
            }

            if (await scwin.f_AddRowUploaded()) {
                $c.sbm.execute(sbm_excelSave);

            } else {
                //ds_excel.removeAll()();
                ds_temp.removeAll();
                ds_upload.removeAll();
                await $c.gus.cfAlertMsg("업로드작업이 취소되었습니다.");
            }
        }
    }
};

scwin.sbm_excelSave_submitdone = async function (e) {
    //ds_excel.removeAll();
    ds_temp.removeAll();
    ds_upload.removeAll();

    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        await $c.gus.cfAlertMsg("업로드작업이 완료되었습니다.");
        scwin.f_Retrieve();

    } else { //실패했을경우
        await $c.gus.cfAlertMsg("업로드작업이 취소되었습니다.");
    }
};

//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
    ds_saleCreditInfo.insertRow();

    //tobe추가 : 그리드 getRowPosition셋팅
    gr_saleCreditInfo.setFocusedCell(ds_saleCreditInfo.getRowCount() - 1, 3);

    ds_saleCreditInfo.setCellData(ds_saleCreditInfo.getRowPosition(), "regYy", ed_regYy.getValue());
    ds_saleCreditInfo.setCellData(ds_saleCreditInfo.getRowPosition(), "regId", scwin.g_sUserId);
    ds_saleCreditInfo.setCellData(ds_saleCreditInfo.getRowPosition(), "gbn", "1");
    ds_saleCreditInfo.setCellData(ds_saleCreditInfo.getRowPosition(), "tmnYn", "0");
    ds_saleCreditInfo.setCellData(ds_saleCreditInfo.getRowPosition(), "tmnDt", "");
    ds_saleCreditInfo.setCellData(ds_saleCreditInfo.getRowPosition(), "regDept", scwin.g_sAcctDeptCd);
    ds_saleCreditInfo.setCellData(ds_saleCreditInfo.getRowPosition(), "grtInst", "서울보증보험");
};

//-------------------------------------------------------------------------
// 행삭제
//-------------------------------------------------------------------------
scwin.f_delMarked = function () {
    var checkIdx = gr_saleCreditInfo.getCheckedIndex("num");
    var focusRow = 0;
    focusRow = ds_saleCreditInfo.getRowPosition(); //현재 포커스 되어있는 행

    for (i = 0; i < checkIdx.length; i++) {
        if (ds_saleCreditInfo.getRowStatus(checkIdx[i]) != "C") {
            ds_saleCreditInfo.deleteRow(checkIdx[i]);
            gr_saleCreditInfo.setCellChecked(checkIdx[i], "num", false);
            gr_saleCreditInfo.setCellReadOnly(checkIdx[i], "num", true);

        } else if (ds_saleCreditInfo.getRowStatus(checkIdx[i]) == "C") {
            ds_saleCreditInfo.removeRow(checkIdx[i]);
        }

    }

    gr_saleCreditInfo.setFocusedCell(focusRow, 3);
};

//-------------------------------------------------------------------------
// 행취소
//-------------------------------------------------------------------------
scwin.f_Undo = function () {
    var focusRow = 0;
    focusRow = ds_saleCreditInfo.getRowPosition(); //현재 포커스 되어있는 행

    $c.data.undoAll(ds_saleCreditInfo);

    for (var i = 0; i < ds_saleCreditInfo.getRowCount(); i++) {
        if (gr_saleCreditInfo.getCellReadOnly(i, "num")) {
            gr_saleCreditInfo.setCellReadOnly(i, "num", false);
        }
    }

    gr_saleCreditInfo.setFocusedCell(focusRow, 3); //포커스는 전과 같게 유지
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (e) {
    // 변경된 사항이 없으면 저장할수 없음.
    if (ds_saleCreditInfo.getModifiedIndex().length < 1) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    if (await scwin.f_check() == false) {
        return;
    }

    // 저장확인 
    if (await $c.win.confirm("저장하시겠습니까?")) {
        $c.sbm.execute(sbm_save);
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        scwin.f_Retrieve();
    };
};

//-------------------------------------------------------------------------
// 엑셀 Download
//-------------------------------------------------------------------------
scwin.f_ExcelDown = async function () {
    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
        gr_saleCreditInfo.setColumnVisible("num", false);
        gr_saleCreditInfo.setColumnVisible("tmnYn", false);
        gr_saleCreditInfo.setColumnVisible("tmnDt", false);
        gr_saleCreditInfo.setColumnVisible("grtInst", false);

        var options = {
            fileName: "매출채권정보조회.xlsx",
            sheetName: "매출채권정보",
            startRowIndex: 0,
            startColumnIndex: 0,
            type: 1,
            columnMove: true, //그리드 컬럼이동시 이동된 상태로 다운로드 유무 ( "true"인경우 컬럼이동 순서대로 출력 )
            evenRowBackgroundColor: "#f5fff5"//excel파일에서 그리드 body의 짝수줄의 배경색
        };
        await $c.data.downloadGridViewExcel(gr_saleCreditInfo, options);

        gr_saleCreditInfo.setColumnVisible("num", true);
        gr_saleCreditInfo.setColumnVisible("tmnYn", true);
        gr_saleCreditInfo.setColumnVisible("tmnDt", true);
        gr_saleCreditInfo.setColumnVisible("grtInst", true);

    } else {
        return;
    }
};

scwin.f_Upload = async function () {
    //ds_excel.removeAll();
    ds_temp.removeAll();
    ds_upload.removeAll();

    //ds_excel.DataId = fileUploadGDS.NameValue(0, "filePath");
    //ds_excel.Reset();
    //resetForm('frm');


    if (udc_topGrd.getUpExt() == "1") {
        let options = {
            "fileName": "gridDataUpload.csv",
            "status": "C",
            "header": 1,
            "type": "1",
            "startRowIndex": 0,
            "footerExist": 0
        };

        await $c.data.uploadGridViewCSV(gr_upload, options); // CSV를 선택하였을 경우
    } else {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "headerExist": 1,
            "type": "1",
            "startRowIndex": 0,
            "footerExist": 0
        };
        await $c.data.uploadGridViewExcel(gr_upload, options);
    }
};

//-------------------------------------------------------------------------
// 엑셀 Upload 
//-------------------------------------------------------------------------
scwin.f_ExcelUp = function () {
    scwin.f_Retrieve2();
};

//-------------------------------------------------------------------------
// 업로드 자료 추가
//-------------------------------------------------------------------------
scwin.f_AddRowUploaded = async function () {
    //ds_temp.setJSON(ds_excel.getAllJSON());  //ds_temp == ds.excel

    scwin.err_message = "";
    var e_crn = "";

    if (ds_temp.getRowCount() > 0) {
        ds_upload.removeAll();

        for (j = 0; j < ds_temp.getRowCount(); j++) {
            ds_upload.insertRow();

            var row = j;//ds_upload.getRowCount();
            ds_upload.setCellData(row, "regYy", ed_regYy.getValue());

            //특수문자 제거
            var str = /-_+<>@\(\'\"]/gi;

            ds_upload.setCellData(row, "crn", ds_temp.getCellData(j, "crn").replace(str, ""));
            if (await scwin.f_openCommonPopUp('3', "crn", "", row, 'T') == false) {
                e_crn = "Y";
            }

            ds_upload.setCellData(row, "deposit", ds_temp.getCellData(j, "deposit"));

            // 보증금액 0보다 큰값
            if (ds_upload.getCellData(row, "deposit") <= 0) {
                await $c.win.alert("사업자번호 " + ds_upload.getCellData(row, "crn") + " 의 보증금액은 0 으로 입력할수 없습니다.");
                return false;
            }

            ds_upload.setCellData(row, "stCtrtDt", ds_temp.getCellData(j, "stCtrtDt").replace(str, ""));
            ds_upload.setCellData(row, "endCtrtDt", ds_temp.getCellData(j, "endCtrtDt").replace(str, ""));

            //계약시작일자가 더 클경우 체크
            if (!await $c.gus.cfIsAfterDate(ds_upload.getCellData(row, "stCtrtDt"), ds_upload.getCellData(row, "endCtrtDt"))) {
                await $c.win.alert("사업자번호 " + ds_upload.getCellData(row, "crn") + " 의 계약시작일자가 계약종료일자보다 큽니다.");
                return false;
            }

            ds_upload.setCellData(row, "rmk", ds_temp.getCellData(j, "rmk").replace(str, ""));
            ds_upload.setCellData(row, "gbn", ds_temp.getCellData(j, "gbn"));

            if (ds_upload.getCellData(row, "gbn") != "1" && ds_upload.getCellData(row, "gbn") != "2") {
                await $c.win.alert("사업자번호 " + ds_upload.getCellData(row, "crn") + " 의 구분코드는 1 (신용한도) 또는 2 (자유한도)로 입력하세요");
                return false;
            }

            ds_upload.setCellData(row, "grtDocNo", ds_temp.getCellData(j, "grtDocNo"));
            ds_upload.setCellData(row, "regId", scwin.g_sUserId);
            ds_upload.setCellData(row, "tmnYn", "0");
            ds_upload.setCellData(row, "tmnDt", "");
            ds_upload.setCellData(row, "regDept", scwin.g_sAcctDeptCd);
            ds_upload.setCellData(row, "grtInst", "서울보증보험");

            // 필수입력사항에 대해서 Check한다.
            if (!await $c.gus.cfValidate([gr_upload], null, true)) {
                return false;
            }

            if (j == (ds_temp.getRowCount() - 1) && e_crn == "Y") {
                await $c.win.alert("사업자번호 (" + scwin.err_message + ")는 등록된 사업자가 아닙니다.");
                return false;
            }
        }
    }
    return true;
};

//-------------------------------------------------------------------------
// 매출채권 해지
//-------------------------------------------------------------------------
scwin.f_cancel = async function (e) {
    if (ica_tmnDt.getValue().trim() == "") {
        await $c.win.alert("해지일자를 입력하세요");
        return;
    }

    // 저장된 건만 해지 가능.
    var checkIdx = gr_saleCreditInfo.getCheckedIndex("num");
    var j = 1;

    for (i = 0; i < checkIdx.length; i++) {
        if (ds_saleCreditInfo.getRowStatus(checkIdx[i]) == "C") {
            await $c.win.alert("등록된 건만 해지가 가능합니다.");
            return;
        }

        j++;
    }

    if (await scwin.f_check() == false) {
        return;
    }

    //tobe 변경 : tobe상황에 맞게 변경
    // var j = 1;	
    // for ( i = 1 ; i <= ds_saleCreditInfo.CountRow ; i++){
    //     if	(ds_saleCreditInfo.NameValue(i,"num") == "T"){
    //         j++;
    //     }	
    // }


    if (j == 1) {
        await $c.win.alert("선택된 항목이 없습니다.");
        return false;
    }

    if (!await $c.win.confirm("선택한 항목을 해지하시겠습니까?"))
        return false;

    for (i = 0; i < checkIdx.length; i++) {
        ds_saleCreditInfo.setCellData(checkIdx[i], "tmnYn", "1");
        ds_saleCreditInfo.setCellData(checkIdx[i], "tmnDt", ica_tmnDt.getValue());
    }

    $c.sbm.execute(sbm_cancel);
};

scwin.sbm_cancel_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        scwin.f_Retrieve();
    };
};

//-------------------------------------------------------------------------
// 매출채권 해지 취소
//-------------------------------------------------------------------------
scwin.f_tmnCancel = async function (e) {
    if (ds_saleCreditInfo.getCellData(ds_saleCreditInfo.getRowPosition(), "tmnYn") == "0" || ds_saleCreditInfo.getCellData(ds_saleCreditInfo.getRowPosition(), "tmnYn") == "") {
        await $c.win.alert("해지된건이 아닙니다.");
        return;
    }

    if (!await $c.win.confirm("해지취소 하시겠습니까?")) return false;

    ds_saleCreditInfo.setCellData(ds_saleCreditInfo.getRowPosition(), "tmnYn", "0");
    ds_saleCreditInfo.setCellData(ds_saleCreditInfo.getRowPosition(), "tmnDt", "");

    $c.sbm.execute(sbm_tmnCancel);
};

scwin.sbm_tmnCancel_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        scwin.f_Retrieve();
    };
};

scwin.f_check = async function () {
    // 필수 조회조건 입력 여부(등록년도) Check
    if (!await $c.gus.cfValidate([ed_regYy], null, true)) {
        return false;
    }

    if (!await $c.gus.cfValidate([gr_saleCreditInfo], null, true)) {
        return false;
    }

    var checkIdx = gr_saleCreditInfo.getCheckedIndex("num");
    for (i = 0; i < checkIdx.length; i++) {
        //계약시작일자가 더 클경우 체크
        if (!await $c.gus.cfIsAfterDate(ds_saleCreditInfo.getCellData(checkIdx[i], "stCtrtDt"), ds_saleCreditInfo.getCellData(checkIdx[i], "endCtrtDt"))) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            return false;
        }

        // 보증금액 0보다 큰값
        if (ds_saleCreditInfo.getCellData(checkIdx[i], "deposit") <= 0) {
            await $c.win.alert("보증금액은 0 으로 입력할수 없습니다.");
            return false;
        }
    }
};

scwin.gr_saleCreditInfo_onheaderclick = function (headerId) {
    var i = 0;

    if (headerId == "column30") {
        if (gr_saleCreditInfo.getHeaderValue('column30')) {
            for (i = 0; i < ds_saleCreditInfo.getRowCount(); i++) {
                if (ds_saleCreditInfo.getCellData(i, "tmnYn") == "1") {
                    ds_saleCreditInfo.setCellData(i, "num", "F");
                }
            }
        }
        // else {
        //     for (i = 0; i < ds_saleCreditInfo.getRowCount(); i++) {
        //         ds_saleCreditInfo.setCellData(i, "num", "F");
        //     }
        // }
    }
};

//tobe 삭제 : 입력후, 바로 돋보기 버튼 클릭하면 aferedit이랑 같이 작동되어 팝업 두번호출됨.
// scwin.gr_saleCreditInfo_ontextimageclick = function (rowIndex, columnIndex) {
//     scwin.row = rowIndex;
//     var colId = gr_saleCreditInfo.getColumnID(columnIndex);

//     if (colId == "crn") {
