//for=gr_saleCreditInfo event=OnExit(row,colid,olddata)
scwin.gr_saleCreditInfo_onafteredit = async function (rowIndex, columnIndex, value) {

    var colId = gr_saleCreditInfo.getColumnID(columnIndex);

    if (colId == 'crn') await scwin.f_checkCommonPopUp('2', "crn", "crnNm", rowIndex);

    if (colId == 'deposit') if (value == "") ds_saleCreditInfo.setCellData(rowIndex, "deposit", 0);
};

//해지된 건은 수정 불가
scwin.gr_saleCreditInfo_oncellclick = function (rowIndex, columnIndex, columnId) {
    if (rowIndex > -1) {
        if (ds_saleCreditInfo.getCellData(rowIndex, "tmnYn") == "1") {
            ds_saleCreditInfo.setCellData(rowIndex, "num", "F");
            gr_saleCreditInfo.setColumnReadOnly("num", true);
            gr_saleCreditInfo.setColumnReadOnly("crn", true);
            gr_saleCreditInfo.setColumnReadOnly("deposit", true);
            gr_saleCreditInfo.setColumnReadOnly("stCtrtDt", true);
            gr_saleCreditInfo.setColumnReadOnly("endCtrtDt", true);
            gr_saleCreditInfo.setColumnReadOnly("rmk", true);
            gr_saleCreditInfo.setColumnReadOnly("gbn", true);
            gr_saleCreditInfo.setColumnReadOnly("grtDocNo", true);

        } else {
            gr_saleCreditInfo.setColumnReadOnly("num", false);
            gr_saleCreditInfo.setColumnReadOnly("crn", false);
            gr_saleCreditInfo.setColumnReadOnly("deposit", false);
            gr_saleCreditInfo.setColumnReadOnly("stCtrtDt", false);
            gr_saleCreditInfo.setColumnReadOnly("endCtrtDt", false);
            gr_saleCreditInfo.setColumnReadOnly("rmk", false);
            gr_saleCreditInfo.setColumnReadOnly("gbn", false);
            gr_saleCreditInfo.setColumnReadOnly("grtDocNo", false);
        }
    }
};

